import { AuthService } from '../auth.service';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';

jest.mock('jsonwebtoken');
jest.mock('bcryptjs');

describe('AuthService', () => {
  let authService: AuthService;
  const mockSecretKey = 'test-secret-key';
  const mockPayload = {
    id: 'user123',
    email: 'test@example.com',
    role: 'admin'
  };

  beforeEach(() => {
    authService = new AuthService(mockSecretKey);
    jest.clearAllMocks();
  });

  describe('generateToken', () => {
    it('should generate a valid JWT token', async () => {
      const mockToken = 'mock.jwt.token';
      (jwt.sign as jest.Mock).mockReturnValue(mockToken);

      const token = await authService.generateToken(mockPayload);

      expect(jwt.sign).toHaveBeenCalledWith(
        mockPayload,
        mockSecretKey,
        { expiresIn: '24h' }
      );
      expect(token).toBe(mockToken);
    });

    it('should throw error when token generation fails', async () => {
      (jwt.sign as jest.Mock).mockImplementation(() => {
        throw new Error('Signing error');
      });

      await expect(authService.generateToken(mockPayload))
        .rejects
        .toThrow('Token generation failed: Signing error');
    });
  });

  describe('verifyToken', () => {
    it('should verify and decode a valid token', async () => {
      (jwt.verify as jest.Mock).mockReturnValue(mockPayload);

      const result = await authService.verifyToken('valid.token');

      expect(jwt.verify).toHaveBeenCalledWith('valid.token', mockSecretKey);
      expect(result).toEqual(mockPayload);
    });

    it('should throw specific error for expired tokens', async () => {
      const expiredError = new Error('Token expired');
      expiredError.name = 'TokenExpiredError';
      (jwt.verify as jest.Mock).mockImplementation(() => {
        throw expiredError;
      });

      await expect(authService.verifyToken('expired.token'))
        .rejects
        .toThrow('Token has expired');
    });

    it('should throw generic error for invalid tokens', async () => {
      (jwt.verify as jest.Mock).mockImplementation(() => {
        throw new Error('Invalid signature');
      });

      await expect(authService.verifyToken('invalid.token'))
        .rejects
        .toThrow('Token verification failed: Invalid signature');
    });
  });

  describe('hashPassword', () => {
    it('should hash password using bcrypt', async () => {
      const mockHash = 'hashed_password';
      (bcrypt.hash as jest.Mock).mockResolvedValue(mockHash);

      const hash = await authService.hashPassword('password123');

      expect(bcrypt.hash).toHaveBeenCalledWith('password123', 10);
      expect(hash).toBe(mockHash);
    });
  });

  describe('comparePassword', () => {
    it('should return true for matching passwords', async () => {
      (bcrypt.compare as jest.Mock).mockResolvedValue(true);

      const result = await authService.comparePassword(
        'password123',
        'hashed_password'
      );

      expect(bcrypt.compare).toHaveBeenCalledWith(
        'password123',
        'hashed_password'
      );
      expect(result).toBe(true);
    });

    it('should return false for non-matching passwords', async () => {
      (bcrypt.compare as jest.Mock).mockResolvedValue(false);

      const result = await authService.comparePassword(
        'wrongpassword',
        'hashed_password'
      );

      expect(result).toBe(false);
    });
  });
});

